mapper.sql:
SELECT
	  COUNT(1) OVER()				AS TOTAL_CNT
	, COUNT(1) OVER() - ROW_NUMBER() OVER(ORDER BY A.ACTN_HSTY_SN DESC) + 1 AS LINE_NO 
	, A.ACTN_HSTY_SN				
	, A.SBJCT_ID					
	, A.USER_ID						
	, A.ACTV_HSTRY_CD				
	, A.ACTV_HSTRY_CTS				
	, A.CNTN_DVC_TYCD				
	, A.RGTR_IP						
	, A.RGTR_ID						
	, A.FRST_INQ_DTTM					
FROM TB_LOG_LESSON_ACTN_HSTY A
WHERE A.SBJCT_ID = #{crsCreCd}

	AND A.ACTN_HSTY_SN = #{actnHstySn}


	AND A.USER_ID = #{userId}


	AND A.ACTV_HSTRY_CD = #{actnHstyCd}


	AND A.CNTN_DVC_TYCD = #{deviceTypeCd}


	AND A.RGTR_IP = #{regIp}

mapper.insert:
	/*
		 SQL ID : LogLessonActnHstyDAO.insertLessonActnHsty
		 설  명 : 강의실 활동 로그 등록
 	*/
	INSERT INTO TB_LOG_LESSON_ACTN_HSTY (
		  ACTN_HSTY_SN
		, SBJCT_ID
		, USER_ID  
		, ACTV_HSTRY_CD
		, ACTV_HSTRY_CTS
		, CNTN_DVC_TYCD
		, RGTR_IP
		, RGTR_ID
		, FRST_INQ_DTTM
	) VALUES (
		  #{actnHstySn}
	    , #{crsCreCd}
		, #{userId}
		, #{actnHstyCd}
		, #{actnHstyCts}
		, #{deviceTypeCd}
		, #{regIp}
		, #{rgtrId}
		, FN_DTTM()
	)
